from source import wrap

def test_wrap_includes_trailing_text_after_last_break():
    result = wrap('aaa bbb ccc', 4)
    assert len(result) == 3, (
        f"wrap('aaa bbb ccc', 4) returned {result!r} with {len(result)} element(s); "
        "the trailing segment remaining after the last break is not appended to lines"
    )
    assert 'ccc' in result[-1], (
        f"Last element {result[-1]!r} should contain 'ccc' — the final text chunk was lost"
    )
